class Solution:
    def evaluate(self, expression: str) -> int:
        import re
        toks = re.findall(r"[a-z]+|[-]?\d+", expression)
        it = iter(toks)
        def parse(scope):
            t = next(it)
            if t.lstrip("-").isdigit(): return int(t)
            if t in scope: return scope[t]
            op = t
            if op == "let":
                scope = dict(scope)
                while True:
                    v = next(it)
                    if v == ")": return parse(scope)
                    val = parse(scope)
                    scope[v] = val
            else:
                a = parse(scope)
                b = parse(scope)
                next(it)
                return a + b if op == "add" else a * b
        return parse({})

