class Solution {
    vector<string> tok; int i=0;
    int parse(unordered_map<string,int>& sc) {
        string t=tok[i++];
        if(isdigit(t[0])||(t.size()>1&&t[0]=='-')) return stoi(t);
        if(sc.count(t)) return sc[t];
        string op=t;
        if(op=="let"){
            while(true){
                string v=tok[i++];
                if(v==")") return parse(sc);
                int val=parse(sc); sc[v]=val;
            }
        }
        int a=parse(sc), b=parse(sc); i++;
        return op=="add"?a+b:a*b;
    }
public:
    int evaluate(string expression) {
        string cur; for(char c:expression){ if(c=='('||c==')'||c==' '){ if(!cur.empty()){ tok.push_back(cur); cur.clear(); } if(c!=' ') tok.push_back(string(1,c)); } else cur.push_back(c); }
        if(!cur.empty()) tok.push_back(cur);
        unordered_map<string,int> sc; return parse(sc);
    }
};

